mapper.update:
    	UPDATE 
    		HC_MEMBER
    	SET	
    		MEM_BEFO_PWD = #{memBefoPwd}
    		, MEM_PWD = #{memPwd}
    	WHERE 
    		1=1
	        AND MEM_STAT != 'delete'
	    	AND MEM_ID = #{memId}

mapper.select:
SELECT COUNT(*)
FROM HC_MEMBER hm
WHERE hm.MEM_SNO = #{memSno}

	AND hm.MEM_SEQ != #{memSeq}
